      <div className="flex items-center gap-2 max-w-[400px]">
        <RadioGroupItem value="3" id={`${id}-3`} />
        <Label htmlFor={`${id}-3`}>Option 3</Label>
      </div>
    </RadioGroup>
  );
}

export { Component };

